# -----------------------

# 7. Instruction

# -----------------------

instruction = (
"Extract the core computer science concepts from this lecture. "
"Return ONLY a newline-separated list of unique concepts. "
"No explanations."
)

# -----------------------

# 8. Chunk Slides

# -----------------------

CHUNK_SIZE = 4

chunks = [
lecture_data[i:i + CHUNK_SIZE]
for i in range(0, len(lecture_data), CHUNK_SIZE)
]

all_concepts = set()

# -----------------------

# 9. Run Model

# -----------------------

for chunk in chunks:
    lecture_json = json.dumps(chunk, separators=(",", ":"))

prompt = f"""### Instruction:


{instruction}

### BEGIN_LECTURE_JSON

{lecture_json}

### END_LECTURE_JSON

### Output:

"""


inputs = tokenizer(
    prompt,
    return_tensors="pt",
    truncation=True,
    max_length=2048
).to(model.device)

with torch.no_grad():
    outputs = model.generate(
        **inputs,
        max_new_tokens=150,
        temperature=0.2,
        do_sample=False,
        eos_token_id=tokenizer.eos_token_id
    )

decoded = tokenizer.decode(outputs[0], skip_special_tokens=True)

# remove prompt from output
response = decoded[len(prompt):].strip()

for concept in response.split("\n"):
    concept = concept.strip()
    if concept:
        all_concepts.add(concept)


# -----------------------

# 10. Final Output

# -----------------------

print("\n=== FINAL CONCEPT LIST ===\n")

for concept in sorted(all_concepts):
    print(concept)

